int maximumProduct(int* nums, int n) {
    qsort(nums,n,sizeof(int),cmp);
    int a=nums[n-1]*nums[n-2]*nums[n-3];
    int b=nums[0]*nums[1]*nums[n-1];
    return a>b?a:b;
}
